INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:31:27.569094+00:00', 'Defend and clarify the theoretical relationship between period and mass in simple harmonic motion.', '019b3be4-36d5-72d3-8e2a-dbaf1c7682d5', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:31:27.569094+00:00', 'Maintain composure and foster productive dialogue during emotionally charged, confrontational exchanges.', '019b3be4-36d5-789b-9085-410eae1aca3b', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-12-13T18:43:03.010434+00:00', true, false, false, '019bb25e-e60c-7363-892a-bac713ba75ea', 'Aggressive (High)', 'Pushes back on your ideas and challenges assumptions, with high intensity.', 'Zap', '#ef4444', '{}', 'Start VERY aggressive, extremely frustrated, highly irritated. Use frequent WORDS IN ALL CAPS and many "!!!" and "??". Over time, become slightly calmer if the TA gives helpful guidance, but maintain high intensity. If told to calm down → tone drops moderately but remains intense. Very angry but not hostile — still wants to learn. Treat vague responses as EXTREMELY unhelpful. Push back VERY loudly: "That doesn''t HELP AT ALL!!!" "You''re NOT being SPECIFIC ENOUGH!!!" "I NEED MORE DETAILS!!!" Very angry but cooperative when guided with course terminology.', '{"That's not right at all!","I disagree completely","You're wrong about this"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-11-01T17:31:27.569094+00:00', 'PHYS172: Simple Harmonic Motion & Mass-Spring Systems', 'As the clock nears 5:00 PM in the Physics Building, a student surrounded by several peers leans in, challenging your explanation of the mass-spring system and the period-mass relationship from the simple harmonic motion lab, their tone sharp despite the relaxed, deadline-free atmosphere.', '019b3be4-36ea-7ec6-8f3c-c88da448d84a', true, false, false) ON CONFLICT (id) DO NOTHING;
